SELECT tot_score
FROM game_scores
WHERE user_id = 1 AND version_id = 1;

SELECT sub_time, tot_score, game_mode, os_name
FROM game_scores
WHERE game_mode = 'single-player';

SELECT version_id, AVG(tot_score) AS average_score
FROM game_scores
GROUP BY version_id;

SELECT score
FROM leaderboards
WHERE leaderboard_id = 0;

SELECT tot_score 
FROM game_scores 
WHERE score_id = 1;

SELECT COUNT(DISTINCT gs.user_id) AS user_count
FROM game_scores gs
WHERE gs.builders_at_construction_site >= 100;
